.darma-loader-uiverse-newton-swing {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-newton-swing__newtons-cradle {
 --uib-size: 50px;
 --uib-speed: 1.2s;
 --uib-color: #474554;
 position: relative;
 display: flex;
 align-items: center;
 justify-content: center;
 width: var(--uib-size);
 height: var(--uib-size);
}

.darma-loader-uiverse-newton-swing__newtons-cradle__dot {
position: relative;
display: flex;
align-items: center;
height: 100%;
width: 25%;
transform-origin: center top;
}

.darma-loader-uiverse-newton-swing__newtons-cradle__dot::after {
content: '';
display: block;
width: 100%;
height: 25%;
border-radius: 50%;
background-color: var(--uib-color);
}

.darma-loader-uiverse-newton-swing__newtons-cradle__dot:first-child {
animation: darma-loader-uiverse-newton-swing-swing var(--uib-speed) linear infinite;
}

.darma-loader-uiverse-newton-swing__newtons-cradle__dot:last-child {
animation: darma-loader-uiverse-newton-swing-swing2 var(--uib-speed) linear infinite;
}

@keyframes darma-loader-uiverse-newton-swing-swing {
0% {
transform: rotate(0deg);
animation-timing-function: ease-out;
}

25% {
transform: rotate(70deg);
animation-timing-function: ease-in;
}

50% {
transform: rotate(0deg);
animation-timing-function: linear;
}
}

@keyframes darma-loader-uiverse-newton-swing-swing2 {
0% {
transform: rotate(0deg);
animation-timing-function: linear;
}

50% {
transform: rotate(0deg);
animation-timing-function: ease-out;
}

75% {
transform: rotate(-70deg);
animation-timing-function: ease-in;
}
}

